Variations.Variation:
/* for mBlendedCenterN and mBlendedBordersN
projNormal.r - smoothness projNormal.g - normal.g projNormal.b - projNormal.a - normal.r
smoothness - loaded from projNormal.r */ #define USE_TRI_PLANAR_R #define USE_TRI_PLANAR_B #define PROJNORMAL_TERRAIN_FORMAT

CodeInjections.CodeInjection:
    uniform float4 uvScaleCB;
#if defined( CLIP_ALPHA )
    uniform float4 alphaRemap;
#endif

sampler2D mBlendedCenter;
sampler2D mBlendedBorders;
sampler2D mBlendedCenterN;
sampler2D mBlendedBordersN;

#if ( defined( USE_TRI_PLANAR_B ) || defined( USE_TRI_PLANAR_R ) )
    float2 texCoordsX    : TEXCOORDn;
    float2 texCoordsY    : TEXCOORDn;
    float2 texCoordsZ    : TEXCOORDn;
#endif

#if ( defined( USE_TRI_PLANAR_B ) || defined( USE_TRI_PLANAR_R ) )
    float3 fullWorldPosition = worldPosition + float3(invViewMatrix[0][3], invViewMatrix[1][3], invViewMatrix[2][3]);
    Out.texCoordsX = fullWorldPosition.yz;
    Out.texCoordsY = fullWorldPosition.xz;
    Out.texCoordsZ = fullWorldPosition.xy;
#endif

/*
globals.gVertexColor.r - opacity  for mBlendedCenter   [ 0 - mBlendedCenter  not visible, 1 - fully visible ]
globals.gVertexColor.g - softness for mBlendedCenter and mBlendedBorders  [ 0 - sharp transition, 1 - soft transition ]
globals.gVertexColor.b - opacity  for mBlendedBorders  [ 0 - mBlendedBorders not visible, 1 - fully visible ]
globals.gVertexColor.a - opacity control
*/
    float4 gVertexColor;
    float  gMaskCenter;
    float  gMaskBorders;
    float4 gBlendedCenter;
    float4 gBlendedBorders;
    float4 gBlendedCenterN;
    float4 gBlendedBordersN;
    float2 gUVs;

#if ( defined( USE_TRI_PLANAR_B ) || defined( USE_TRI_PLANAR_R ) )
    float3 mAbsNormal = abs(In.vs.worldNormal);
    mAbsNormal /= (mAbsNormal.x + mAbsNormal.y + mAbsNormal.z);
    globals.gUVs = mAbsNormal.x > mAbsNormal.y ? (mAbsNormal.x > mAbsNormal.z ? In.vs.texCoordsX : In.vs.texCoordsZ) : (mAbsNormal.y > mAbsNormal.z ? In.vs.texCoordsY : In.vs.texCoordsZ);
#endif
    globals.gVertexColor     = In.vs.vertexColor.rgba;
#if defined( USE_TRI_PLANAR_R )
    globals.gBlendedCenter  = tex2D( mBlendedCenter, uvScaleCB.xy*globals.gUVs ).rgba;
    globals.gBlendedCenterN = tex2D( mBlendedCenterN, uvScaleCB.xy*globals.gUVs ).rgba;
#else
    globals.gBlendedCenter   = tex2D( mBlendedCenter , uvScaleCB.xy * In.vs.ALBEDOMAP_TEXCOORD ).rgba;
    globals.gBlendedCenterN  = tex2D( mBlendedCenterN , uvScaleCB.xy * In.vs.ALBEDOMAP_TEXCOORD ).rgba;
#endif
#if defined( USE_TRI_PLANAR_B )
    globals.gBlendedBorders  = tex2D( mBlendedBorders, uvScaleCB.zw*globals.gUVs ).rgba;
    globals.gBlendedBordersN = tex2D( mBlendedBordersN, uvScaleCB.zw*globals.gUVs ).rgba;
#else
    globals.gBlendedBorders  = tex2D( mBlendedBorders, uvScaleCB.zw * In.vs.ALBEDOMAP_TEXCOORD ).rgba;
    globals.gBlendedBordersN = tex2D( mBlendedBordersN, uvScaleCB.zw * In.vs.ALBEDOMAP_TEXCOORD ).rgba;
#endif
    float4 mBaseMap      = float4( 1, 1, 1, 1 );
#if defined( ALBEDO_MAP )
    mBaseMap             = tex2D( baseMap, In.vs.ALBEDOMAP_TEXCOORD).rgba;
#endif
    float4 mTmp          = saturate( ( globals.gVertexColor.rgba - mBaseMap.aaaa ) / ( 0.01 + globals.gVertexColor.g ) );
    globals.gMaskCenter  = mTmp.r;
    globals.gMaskBorders = mTmp.b;

#if defined( NORMAL_MAP )
   float3 mNormal   = tex2D( normalMap, In.vs.NORMALMAP_TEXCOORD).xyz - 0.5;
   float4 mBlenCenterN  = globals.gBlendedCenterN.rgba   * 2.0 - 1.0;
   float4 mBlenBordersN = globals.gBlendedBordersN.rgba  * 2.0 - 1.0;
   #if defined( PROJNORMAL_TERRAIN_FORMAT )
       mBlenCenterN.r  = globals.gBlendedCenterN.a  * 2.0 - 1.0;
       //mBlenCenterN.b  = sqrt(1.0 - dot(mBlenCenterN.xy, mBlenCenterN.xy));
       mBlenBordersN.r = globals.gBlendedBordersN.a * 2.0 - 1.0;
       //mBlenBordersN.b = sqrt(1.0 - dot(mBlenBordersN.xy, mBlenBordersN.xy));
   #endif
   mNormal = lerp( mNormal, mBlenCenterN.rgb,  globals.gMaskCenter );
   mNormal = lerp( mNormal, mBlenBordersN.rgb, globals.gMaskBorders ); 
   return mNormal;
#endif

#if defined(ALBEDO_MAP)
    diffuseColor.rgb = lerp( diffuseColor.rgb, globals.gBlendedCenter.rgb,  globals.gMaskCenter );
    diffuseColor.rgb = lerp( diffuseColor.rgb, globals.gBlendedBorders.rgb, globals.gMaskBorders );
#endif

#if defined( SPECULAR ) && defined( GLOSS_MAP )    
    #if defined( PROJNORMAL_TERRAIN_FORMAT )
        float3 mSpecular  = tex2D(glossMap, In.vs.GLOSSMAP_TEXCOORD);
        float mSmoothness = 0.0; 
        mSmoothness = lerp( mSpecular.r, globals.gBlendedCenterN.r,   globals.gMaskCenter );
        mSmoothness = lerp( mSpecular.r, globals.gBlendedBordersN.r,  globals.gMaskBorders );        
        roughness = 1.0 - mSmoothness;
        bakedAO   = mSpecular.g;
        metalness = 0.0;
    #endif
#endif

#if defined( CLIP_ALPHA )
    float mAlpha = mBaseMap.a*globals.gVertexColor.a;
    mAlpha = lerp( alphaRemap.z, alphaRemap.w, mAlpha );
    mAlpha = saturate(lerp( mAlpha, 1.0 , globals.gVertexColor.a) );
    mAlpha = lerp( alphaRemap.x, alphaRemap.y, mAlpha );
    clip(mAlpha - 0.03);
#endif
